import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface WantedUserData {
userId: number;
username: string;
figure: string;
wantedLevel: number;

// ✅ NEW (from composer #5)
maxRemainingSeconds: number;

// ✅ NEW (from composer #6)
chargesList: string[]; // raw list, duplicates allowed
}

export class WantedListParser implements IMessageParser {
private _data: WantedUserData[] = [];

public flush(): boolean {
this._data = [];
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean {
const count = wrapper.readInt();
const list: WantedUserData[] = [];

for (let i = 0; i < count; i++) {
const userId = wrapper.readInt();
const username = wrapper.readString();
const figure = wrapper.readString();
const wantedLevel = wrapper.readInt();

// ✅ matches composer: maxRemainingSeconds
const maxRemainingSeconds = wrapper.readInt();

// ✅ matches composer: charges list size + strings
const chargesCount = wrapper.readInt();
const chargesList: string[] = [];

for (let c = 0; c < chargesCount; c++) {
const chargeName = wrapper.readString();
if (chargeName && chargeName.trim().length) chargesList.push(chargeName.trim());
}

list.push({
userId,
username,
figure,
wantedLevel,
maxRemainingSeconds: Math.max(0, maxRemainingSeconds),
chargesList
});
}

this._data = list;

// 🔥 Broadcast event so UI updates immediately
window.dispatchEvent(
new CustomEvent('wanted_list_update', { detail: this._data })
);

return true;
}

public getWantedUsers(): WantedUserData[] {
return this._data;
}
}
